definition.script:
// Scripted Pipeline: JFrog CLI + npm + Build Info (matches job project-examples-npm-jfrog)
// Requires: Pipeline, Git, JFrog Jenkins Plugin, Node.js + npm on agent
node {
    timestamps {
        try {
            env.CI = 'true'
            env.JFROG_CLI_AVOID_NEW_VERSION_WARNING = 'true'
            env.JFROG_CLI_HIDE_SURVEY = 'true'
            env.JFROG_CLI_SERVER_ID = params.JFROG_SERVER_ID
            env.JFROG_BINARY_PATH = tool 'jfrog-cli'

            def jfrogBuildName = (params.JFROG_BUILD_NAME?.trim() ?: env.JOB_BASE_NAME)
            def jfrogBuildNumber = env.BUILD_NUMBER
            env.JFROG_BUILD_NAME = jfrogBuildName
            env.JFROG_BUILD_NUMBER = jfrogBuildNumber

            stage('Checkout') {
                git 'https://github.com/JFrog-MengKe/project-examples'
            }

            stage('JFrog npm (install + record deps)') {
                dir('npm-example') {
                    jf([
                        'npm-config',
                        '--server-id-resolve', params.JFROG_SERVER_ID,
                        '--server-id-deploy', params.JFROG_SERVER_ID,
                        '--repo-resolve', params.NPM_REPO_RESOLVE,
                        '--repo-deploy', params.NPM_REPO_DEPLOY
                    ])
                    def installArgs = params.NPM_INSTALL_ARGS?.trim() ? params.NPM_INSTALL_ARGS.trim().split(/\s+/).findAll { it } as List : []
                    jf(['npm', 'install'] + installArgs + ['--build-name', jfrogBuildName, '--build-number', jfrogBuildNumber])
                }
            }

            stage('Enrich build info (env + git)') {
                jf(['rt', 'build-collect-env', jfrogBuildName, jfrogBuildNumber])
                jf(['rt', 'build-add-git', jfrogBuildName, jfrogBuildNumber])
            }

            stage('Publish npm package') {
                dir('npm-example') {
                    jf(['npm', 'publish', '--build-name', jfrogBuildName, '--build-number', jfrogBuildNumber])
                }
            }

            stage('Publish build info') {
                jf(['rt', 'build-publish', jfrogBuildName, jfrogBuildNumber])
            }

            stage('Security Check') {
                jf 'bs'
            }
        } finally {
            stage('Cleanup npm workspace') {
                sh '''set +e
echo "Removing npm-example/node_modules"
rm -rf "${WORKSPACE}/npm-example/node_modules" || true
'''
            }
        }
    }
}
